+        : TValue extends readonly (infer TItem)[]
+          ? ReplaceRecur<TItem, TInput, TOutput>[]
+          : TValue extends object
+            ? { [TKey in keyof TValue]: ReplaceRecur<TValue[TKey], TInput, TOutput> }
+            : TValue;
