+/**
+ * Creates a recursive schema.
+ *
+ * @param wrapped The schema containing recur placeholders.
+ *
+ * @returns A recursive schema.
+ */
+// @__NO_SIDE_EFFECTS__
+export function recursive<
+  const TWrapped extends BaseSchema<unknown, unknown, BaseIssue<unknown>>,
+>(wrapped: TWrapped): RecursiveSchema<TWrapped> {
+  const schema = {
+    kind: 'schema' as const,
+    type: 'recursive' as const,
+    reference: recursive,
+    expects: wrapped.expects,
+    async: false as const,
+    wrapped,
+    '~recur': true as const,
+    get '~standard'() {
+      return _getStandardProps(this);
+    },
+    '~run'(dataset: Parameters<TWrapped['~run']>[0], config: Parameters<TWrapped['~run']>[1]) {
+      return _resolveRecur(wrapped, schema)['~run'](dataset, config);
+    },
+  };
+  return schema as RecursiveSchema<TWrapped>;
+}
+
+/**
+ * Resolves recur placeholders in schema child positions.
+ *
+ * @param schema The schema to resolve.
+ * @param recurSchema The recursive schema.
+ *
+ * @returns The resolved schema.
+ *
+ * @internal
+ */
+function _resolveRecur(
+  schema: BaseSchema<unknown, unknown, BaseIssue<unknown>>,
+  recurSchema: BaseSchema<unknown, unknown, BaseIssue<unknown>>
+): BaseSchema<unknown, unknown, BaseIssue<unknown>> {
+  if (schema === Recur) {
+    return recurSchema;
+  }
+
+  const properties: Record<string, unknown> = {};
+  if ('item' in schema) {
+    properties.item = _resolveRecur(schema.item as typeof schema, recurSchema);
+  }
+  if ('value' in schema) {
+    properties.value = _resolveRecur(schema.value as typeof schema, recurSchema);
+  }
+  if ('rest' in schema) {
+    properties.rest = _resolveRecur(schema.rest as typeof schema, recurSchema);
+  }
+  if ('key' in schema && typeof schema.key !== 'string') {
+    properties.key = _resolveRecur(schema.key as typeof schema, recurSchema);
+  }
+  if ('entries' in schema) {
+    properties.entries = Object.fromEntries(
+      Object.entries(schema.entries as Record<string, typeof schema>).map(
+        ([key, value]) => [key, _resolveRecur(value, recurSchema)]
+      )
+    );
+  }
+  if ('options' in schema && Array.isArray(schema.options)) {
+    properties.options = schema.options.map((option) =>
+      _resolveRecur(option as typeof schema, recurSchema)
+    );
+  }
+  if ('pipe' in schema) {
+    properties.pipe = schema.pipe.map((item: typeof schema) =>
+      item.kind === 'schema' ? _resolveRecur(item, recurSchema) : item
+    );
+  }
+
+  return Object.create(Object.getPrototypeOf(schema), {
+    ...Object.getOwnPropertyDescriptors(schema),
+    ...Object.fromEntries(
+      Object.entries(properties).map(([key, value]) => [
+        key,
+        { configurable: true, enumerable: true, value, writable: true },
+      ])
+    ),
+  });
+}
